// New types for Product Name Generator
export enum ProductNameCategory {
    DESCRIPTIVE = 'DESCRIPTIVE', // Leíró jellegű
    EVOCATIVE = 'EVOCATIVE',   // Hangulatos, érzelmekre ható
    MODERN = 'MODERN',         // Modern, trendi
