interface BusinessPlanDisplayProps {
    plans: BusinessPlan[];
    productDescription: string;
    theme: Theme;
}

export const BusinessPlanDisplay: React.FC<BusinessPlanDisplayProps> = ({ plans, theme }) => {
  const [savedPlans, setSavedPlans] = useState<BusinessPlan[]>([]);

  useEffect(() => {
    try {
        const saved = localStorage.getItem('savedBusinessPlans');
        if (saved) {
            setSavedPlans(JSON.parse(saved));
        }
    } catch (error) {
        console.error("Nem sikerült betölteni a mentett üzleti terveket:", error);
        localStorage.removeItem('savedBusinessPlans');
    }
  }, []);

  const handleSavePlan = (planToSave: BusinessPlan) => {
    const isAlreadySaved = savedPlans.some(p => p.id === planToSave.id);
    if (isAlreadySaved) return;

    const updatedSavedPlans = [...savedPlans, planToSave];
    setSavedPlans(updatedSavedPlans);
    try {
        localStorage.setItem('savedBusinessPlans', JSON.stringify(updatedSavedPlans));
    } catch (error) {
        console.error("Nem sikerült menteni az üzleti tervet:", error);
    }
  };

  const handleDeletePlan = (planIdToDelete: string) => {
    const updatedSavedPlans = savedPlans.filter(p => p.id !== planIdToDelete);
    setSavedPlans(updatedSavedPlans);
    try {
        localStorage.setItem('savedBusinessPlans', JSON.stringify(updatedSavedPlans));
    } catch (error) {
        console.error("Nem sikerült törölni az üzleti tervet:", error);
    }
  };

  const savedPlanIds = useMemo(() => new Set(savedPlans.map(p => p.id)), [savedPlans]);

  return (
    <div className="w-full space-y-8">
        {savedPlans.length > 0 && (
             <div className="animate-fade-in">
                <h3 className="text-xl font-bold text-foreground mb-4">Mentett Tervek</h3>
                <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
                    {savedPlans.map((plan) => (
                        <PlanCard
                            key={plan.id}
                            plan={plan}
                            theme={theme}
                            isSaved={true}
                            onDelete={handleDeletePlan}
                        />
                    ))}
                </div>
                <div className="border-t border-border my-8"></div>
            </div>
        )}

      <div>
          <h3 className="text-xl font-bold text-foreground mb-4">Tervek Gyors Összehasonlítása</h3>
          <BusinessPlanComparisonTable plans={plans} />
      </div>

      <div className="border-t border-border my-8"></div>

      <div>
          <h3 className="text-xl font-bold text-foreground mb-4">Részletes Tervjavaslatok</h3>
          <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
              {plans.map((plan) => (
                <PlanCard 
                    key={plan.id} 
                    plan={plan} 
                    theme={theme}
                    isSaved={savedPlanIds.has(plan.id)}
                    onSave={handleSavePlan}
                />
              ))}
          </div>
      </div>
    </div>
  );
};

import React, { Component, ErrorInfo, ReactNode } from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

interface ErrorBoundaryProps {
  children: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
  errorInfo: ErrorInfo | null;
}

class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null,
    errorInfo: null
  };

  constructor(props: ErrorBoundaryProps) {
    super(props);
  }

  static getDerivedStateFromError(error: Error): Partial<ErrorBoundaryState> {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
    this.setState({ errorInfo });
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: '20px', color: '#ef4444', fontFamily: 'sans-serif', backgroundColor: '#1e293b', minHeight: '100vh', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center' }}>
          <div style={{ maxWidth: '600px', width: '100%' }}>
            <h1 style={{ fontSize: '24px', marginBottom: '16px', textAlign: 'center' }}>Hiba történt az alkalmazás betöltésekor.</h1>
            <div style={{ backgroundColor: 'rgba(239, 68, 68, 0.1)', padding: '20px', borderRadius: '12px', border: '1px solid rgba(239, 68, 68, 0.2)' }}>
              <p style={{ fontWeight: 'bold', marginBottom: '12px', fontSize: '16px' }}>{this.state.error?.message}</p>
              <pre style={{ fontSize: '12px', overflow: 'auto', color: '#fca5a5', whiteSpace: 'pre-wrap', maxHeight: '300px' }}>
                {this.state.errorInfo?.componentStack}
              </pre>
            </div>
            <button 
              onClick={() => window.location.reload()} 
              style={{ marginTop: '24px', width: '100%', padding: '12px 24px', backgroundColor: '#3b82f6', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold', fontSize: '16px', transition: 'background-color 0.2s' }}
            >
              Oldal újratöltése
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

