const parseAndSumCosts = (points: FinancialPoint[] | undefined): string => {
    if (!points || points.length === 0) return '-';

    // Filter out undefined or null points first
    const validPoints = points.filter(p => p && p.cost);

    if (validPoints.length === 0) return '-';

    const total = validPoints.reduce((sum, point) => {
        const num = parseInt(point.cost.replace(/\D/g, ''), 10);
        return sum + (isNaN(num) ? 0 : num);
    }, 0);

    if (total === 0 && validPoints.some(p => p.cost && p.cost.trim() !== '')) {
        return validPoints.map(p => p.cost).join(', ');
    }

    if (total === 0) return '-';

    const isPerMonth = validPoints.some(p => p.cost.includes('/hó'));
    return `${new Intl.NumberFormat('hu-HU').format(total)} HUF${isPerMonth ? '/hó' : ''}`;
};


