export const generateMarketingContent = async (analysisResult: AnalysisResult, userInput: string, brandIdentity?: BrandIdentity | null): Promise<MarketingContent> => {

    let brandContext = "";
    if (brandIdentity) {
        brandContext = `
        Márka Arculat (Ezt vedd figyelembe a hangvételnél és a képek stílusánál):
        - Vizuális hangulat: ${brandIdentity.moodBoardDescription}
        - Színvilág: ${brandIdentity.colorPalette.map(c => c.name).join(', ')}
        - Betűtípus stílus: ${brandIdentity.fontPairing.headlineFont.name} (Címsor), ${brandIdentity.fontPairing.bodyFont.name} (Szöveg)
        `;
    }

    const prompt = `
        Készíts professzionális marketing tartalmakat a következő termékhez/szolgáltatáshoz: "${userInput}".

        Piackutatási elemzés (Kontextus):
        - Célközönség (Personák): ${JSON.stringify(analysisResult.personas)}
        - Piaci helyzet: ${JSON.stringify(analysisResult.marketOverview)}
        - Kulcsszavak: ${JSON.stringify(analysisResult.keywords)}
        - Fájdalompontok/Vágyak (SWOT): ${JSON.stringify(analysisResult.swotAnalysis)}
        ${brandContext}

        A feladatod, hogy generálj egy JSON objektumot (MarketingContent) a következő tartalmakkal, szigorúan MAGYAR nyelven:

        1. **socialMediaPosts**: 3 db közösségi média poszt.
           - Platform: Válassz relevánsat (Facebook, Instagram, LinkedIn, TikTok).
           - Tartalom: Legyen vonzó, az elemzett célközönségre szabva. Használj emojikat. ${brandIdentity ? 'A hangvétel illeszkedjen a megadott márka arculathoz.' : ''}
           - Hashtagek: Releváns magyar hashtagek.
           - Kép Prompt (angolul): Részletes leírás a generálandó képhez, vizuális stílussal (pl. "photorealistic", "minimalist vector"). ${brandIdentity ? 'Kötelezően használd a megadott színpalettát és vizuális hangulatot.' : ''}

        2. **blogPostOutline**: Egy blogbejegyzés vázlata.
           - Cím: Figyelemfelkeltő, SEO-barát.
           - Bevezetés: Rövid kedvcsináló.
           - Szekciók: 3-4 alcím és a hozzájuk tartozó főbb gondolatok (vázlatpontok).
           - Következtetés: Összegzés és Call-to-Action.
           - SEO kulcsszavak: A bejegyzéshez javasolt kulcsszavak.
           - Kép Prompt (angolul): A blogbejegyzéshez illő kiemelt kép leírása. ${brandIdentity ? 'Illeszkedjen a márka vizuális világához.' : ''}

        3. **adCopies**: 2 db hirdetés szöveg.
           - Platform: Google Ads vagy Facebook Ads.
           - Főcím (Headline): Rövid, ütős (Google esetén max 30 karakter).
           - Leírás: Értékajánlat kommunikálása, CTA (Google esetén max 90 karakter).
           - Kép Prompt (angolul): A hirdetéshez tartozó vizuál leírása. ${brandIdentity ? 'Márkahű stílusban.' : ''}

        A válaszod KIZÁRÓLAG a JSON objektum legyen.
    `;

    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: { responseMimeType: "application/json" }
    });
    return robustJsonParse<MarketingContent>(response.text as string);
};

export const generateBuyerPersona = async (analysisResult: AnalysisResult, userInput: string): Promise<BuyerPersona> => {
    const prompt = `Generate buyer persona for ${userInput}. Analysis: ${JSON.stringify(analysisResult.personas)}. JSON format (BuyerPersona).`;
    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: { responseMimeType: "application/json" }
    });
    return robustJsonParse<BuyerPersona>(response.text as string);
};

export const generateImageFromPrompt = async (prompt: string): Promise<string> => {
    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: prompt }] },
        config: {
            imageConfig: { aspectRatio: "1:1" }
        }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
            return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
        }
    }
    throw new Error("No image generated");
};

import React, { useState, useCallback } from 'react';
import type { AnalysisResult, MarketingContent, BuyerPersona, BrandIdentity } from '../types';
import { generateMarketingContent, generateBuyerPersona } from '../services/geminiService';
import { MarketingContentDisplay } from './MarketingContentDisplay';
import { BuyerPersonaDisplay } from './BuyerPersonaDisplay';
import { LoadingSpinner } from './LoadingSpinner';
import { Theme } from '../types';
import { ClipboardDocumentListIcon } from './icons/ClipboardDocumentListIcon';
import { IdentificationIcon } from './icons/IdentificationIcon';
import { DocumentTextIcon } from './icons/DocumentTextIcon';

interface ContentGeneratorViewProps {
    analysisResult: AnalysisResult | null;
    userInput: string;
    theme: Theme;
    brandIdentity?: BrandIdentity | null;
}

const Card: React.FC<{ children: React.ReactNode, className?: string }> = ({ children, className = '' }) => (
    <div className={`bg-card border border-border rounded-xl p-6 ${className}`}>
        {children}
    </div>
);

export const ContentGeneratorView: React.FC<ContentGeneratorViewProps> = ({ analysisResult, userInput, theme, brandIdentity }) => {
    const [marketingContent, setMarketingContent] = useState<MarketingContent | null>(null);
    const [buyerPersona, setBuyerPersona] = useState<BuyerPersona | null>(null);

    const [isLoading, setIsLoading] = useState<Record<string, boolean>>({});
    const [errors, setErrors] = useState<Record<string, string | null>>({});

    const handleGeneration = useCallback(async <T,>(
        key: string,
        generator: () => Promise<T>,
        setter: (data: T) => void
    ) => {
        setIsLoading(prev => ({ ...prev, [key]: true }));
        setErrors(prev => ({ ...prev, [key]: null }));
        try {
            const data = await generator();
            setter(data);
        } catch (e: any) {
            setErrors(prev => ({ ...prev, [key]: e.message || `Hiba történt a(z) ${key} generálása során.` }));
        } finally {
            setIsLoading(prev => ({ ...prev, [key]: false }));
        }
    }, []);

    const handleGenerateMarketingContent = () => {
        if (!analysisResult) return;
        handleGeneration('marketing', () => generateMarketingContent(analysisResult, userInput, brandIdentity), setMarketingContent);
    };

    const handleGenerateBuyerPersona = () => {
        if (!analysisResult) return;
        handleGeneration('persona', () => generateBuyerPersona(analysisResult, userInput), setBuyerPersona);
    };

    if (!analysisResult) {
        return (
            <div className="flex flex-col items-center justify-center h-full rounded-2xl bg-card border border-border text-center p-8 animate-fade-in-up">
                <div className="w-16 h-16 p-2 mb-6 bg-background rounded-2xl border border-border flex items-center justify-center">
                    <DocumentTextIcon className="w-8 h-8 text-primary" />
                </div>
                <h2 className="text-2xl font-bold text-card-foreground">Tartalomgenerátor</h2>
                <p className="mt-2 text-muted-foreground max-w-md">
                    Először végezzen el egy piackutatási elemzést a "Piackutatás" fülön. Az eredmények alapján az AI itt képes lesz marketing tartalmakat generálni.
                </p>
            </div>
        );
    }

    return (
        <div className="w-full max-w-5xl mx-auto animate-fade-in-up space-y-8">
             <div>
                <h1 className="text-3xl font-bold text-foreground">AI Tartalomgenerátor</h1>
                <p className="text-muted-foreground mt-1">
                    Generáljon marketing anyagokat a következő elemzés alapján: <span className="font-semibold text-primary">"{userInput}"</span>
                    {brandIdentity && <span className="block text-xs mt-1 text-emerald-500 font-medium">✓ Márka arculat figyelembevételével</span>}
                </p>
            </div>

            <Card>
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                    <div className="flex flex-col">
                        <h3 className="font-semibold mb-2 flex items-center gap-2 text-lg"><ClipboardDocumentListIcon className="w-5 h-5 text-primary" />Marketing Tartalom</h3>
                        <div className="bg-background border border-border rounded-lg p-4 flex-grow flex flex-col">
                            {isLoading.marketing ? <LoadingSpinner message="Generálás..." /> :
                            marketingContent ? <div className="animate-fade-in-up"><MarketingContentDisplay content={marketingContent} theme={theme} /></div> :
                            <div className="text-center my-auto">
                                <p className="text-sm text-muted-foreground mb-3">Generáljon közösségi média posztokat, blog vázlatot és hirdetési szövegeket, egyedi kép promptokkal.</p>
                                {errors.marketing && <p className="text-red-500 text-xs mb-2">{errors.marketing}</p>}
                                <button onClick={handleGenerateMarketingContent} className="w-full text-sm font-semibold bg-primary text-primary-foreground py-2 px-4 rounded-md hover:bg-primary/90">Tartalomcsomag Generálása</button>
                            </div>}
                        </div>
                    </div>
                    <div className="flex flex-col">
                         <h3 className="font-semibold mb-2 flex items-center gap-2 text-lg"><IdentificationIcon className="w-5 h-5 text-primary" />Vásárlói Perszóna</h3>
                        <div className="bg-background border border-border rounded-lg p-4 flex-grow flex flex-col">
                            {isLoading.persona ? <LoadingSpinner message="Generálás..." /> :
                            buyerPersona ? <div className="animate-fade-in-up"><BuyerPersonaDisplay persona={buyerPersona} /></div> :
                            <div className="text-center my-auto">
                                <p className="text-sm text-muted-foreground mb-3">Hozzon létre egy részletes profilt az ideális vásárlójáról, hogy jobban megértse a célközönségét.</p>
                                {errors.persona && <p className="text-red-500 text-xs mb-2">{errors.persona}</p>}
                                <button onClick={handleGenerateBuyerPersona} className="w-full text-sm font-semibold bg-primary text-primary-foreground py-2 px-4 rounded-md hover:bg-primary/90">Perszóna Generálása</button>
                            </div>}
                        </div>
                    </div>
                </div>
            </Card>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { getMarketAnalysis } from './services/geminiService';
import type { AnalysisResult, AnalysisType, SavedAnalysis, MarketingStrategy, BusinessPlan, BrandIdentity, ProductNameSuggestions, Theme, ActiveView } from './types';
import { InputForm } from './components/InputForm';
import { AnalysisResultDisplay } from './components/AnalysisResultDisplay';
import { LoadingSpinner } from './components/LoadingSpinner';
import { IdeaMentorView } from './components/IdeaMentorView';
import { Sidebar } from './components/Sidebar';
import { LogoIcon } from './components/icons/LogoIcon';
import { MarketingStrategyView } from './components/MarketingStrategyView';
import { ContentGeneratorView } from './components/ContentGeneratorView';
import { AnalysisHistoryView } from './components/AnalysisHistoryView';
import { CalendarView } from './components/CalendarView';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ActiveView>('marketResearch');
  const [theme, setTheme] = useState<Theme>(() => {
    if (typeof window !== 'undefined' && window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      return 'dark';
    }
    return 'light';
  });

  // State for Market Research
  const [productDescription, setProductDescription] = useState<string>('');
  const [industry, setIndustry] = useState<string>('');
  const [geographicalFocus, setGeographicalFocus] = useState<string>('Magyarország');
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [marketingStrategy, setMarketingStrategy] = useState<MarketingStrategy | null>(null);
  const [businessPlans, setBusinessPlans] = useState<BusinessPlan[] | null>(null);
  const [brandIdentity, setBrandIdentity] = useState<BrandIdentity | null>(null);
  const [productNames, setProductNames] = useState<ProductNameSuggestions | null>(null);
  const [isLoadingAnalysis, setIsLoadingAnalysis] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [analysisType, setAnalysisType] = useState<AnalysisType>('product');
  const [keywords, setKeywords] = useState<string>('');
  const [websiteUrl, setWebsiteUrl] = useState<string>('');

  // State for Saved Analyses
  const [savedAnalyses, setSavedAnalyses] = useState<SavedAnalysis[]>([]);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', theme === 'dark');
  }, [theme]);

  // Load saved analyses from localStorage on initial render
  useEffect(() => {
    try {
      const saved = localStorage.getItem('savedAnalyses');
      if (saved) {
        setSavedAnalyses(JSON.parse(saved));
      }
    } catch (error) {
      console.error("Failed to load saved analyses:", error);
      // If parsing fails, clear the corrupted data
      localStorage.removeItem('savedAnalyses');
    }
  }, []);

  // Save analyses to localStorage whenever they change
  useEffect(() => {
    try {
      localStorage.setItem('savedAnalyses', JSON.stringify(savedAnalyses));
    } catch (error) {
      console.error("Failed to save analyses:", error);
    }
  }, [savedAnalyses]);

  const handleAnalysis = async () => {
    if (analysisType === 'product') {
        if (!productDescription.trim()) {
            setError('Kérjük, adjon meg egy termék- vagy szolgáltatásleírást.');
            return;
        }
    } else if (analysisType === 'topic') {
        if (!keywords.trim()) {
            setError('Kérjük, adjon meg kulcsszavakat vagy egy témát.');
            return;
        }
    } else { // website
        if (!websiteUrl.trim()) {
            setError('Kérjük, adjon meg egy weboldal URL-t.');
            return;
        }
    }


    setIsLoadingAnalysis(true);
    setError(null);
    setAnalysisResult(null);
    setMarketingStrategy(null);
    setBusinessPlans(null);
    setBrandIdentity(null);
    setProductNames(null);

    try {
      let params;
      if (analysisType === 'product') {
        params = { type: 'product' as const, description: productDescription, industry, geo: geographicalFocus };
      } else if (analysisType === 'topic') {
        params = { type: 'topic' as const, keywords, geo: geographicalFocus };
      } else {
        params = { type: 'website' as const, url: websiteUrl, geo: geographicalFocus };
      }
      const result = await getMarketAnalysis(params);
      setAnalysisResult(result);
      setActiveView('marketResearch'); // Switch back to results view after analysis
    } catch (e: any) {
      setError(e.message || 'Hiba történt az elemzés készítése közben.');
    } finally {
      setIsLoadingAnalysis(false);
    }
  };

  const currentUserInput = React.useMemo(() => {
    switch (analysisType) {
        case 'product': return productDescription;
        case 'topic': return keywords;
        case 'website': return websiteUrl;
        default: return '';
    }
  }, [analysisType, productDescription, keywords, websiteUrl]);

  const isCurrentResultSaved = React.useMemo(() => {
    if (!analysisResult || !currentUserInput) return false;

    const stringifyStrategy = (strategy: MarketingStrategy | null | undefined): string => {
        if (strategy === null || strategy === undefined) {
            return 'null';
        }
        return JSON.stringify(strategy);
    };

    const currentStrategyJSON = stringifyStrategy(marketingStrategy);

    return savedAnalyses.some(a => 
        a.userInput === currentUserInput && 
        a.result.analysisText === analysisResult.analysisText &&
        stringifyStrategy(a.marketingStrategy) === currentStrategyJSON
    );
  }, [analysisResult, currentUserInput, savedAnalyses, marketingStrategy]);

  const handleSaveAnalysis = () => {
    if (!analysisResult || !currentUserInput) return;

    if (isCurrentResultSaved) {
      return;
    }

    const projectName = window.prompt('Adja meg a projekt nevét:', currentUserInput);
    if (!projectName || !projectName.trim()) {
      return; // User cancelled or entered an empty name
    }

    const newSavedAnalysis: SavedAnalysis = {
      id: `analysis-${Date.now()}`,
      projectName: projectName.trim(),
      savedAt: new Date().toISOString(),
      result: analysisResult,
      userInput: currentUserInput,
      analysisType: analysisType,
      marketingStrategy: marketingStrategy,
    };
    setSavedAnalyses(prev => [newSavedAnalysis, ...prev]);
  };

  const handleDeleteAnalysis = (id: string) => {
    setSavedAnalyses(prev => prev.filter(a => a.id !== id));
  };

  const handleViewSavedAnalysis = (analysis: SavedAnalysis) => {
    setAnalysisResult(analysis.result);
    setAnalysisType(analysis.analysisType);
    setMarketingStrategy(analysis.marketingStrategy || null);
    setBusinessPlans(null); // Reset business plans when loading a saved analysis
    setBrandIdentity(null); // Reset brand identity as well
    setProductNames(null); // Reset product names
    switch(analysis.analysisType) {
      case 'product':
        setProductDescription(analysis.userInput);
        setIndustry(''); // This info is not saved
        setKeywords('');
        setWebsiteUrl('');
        break;
      case 'topic':
        setKeywords(analysis.userInput);
        setProductDescription('');
        setIndustry('');
        setWebsiteUrl('');
        break;
      case 'website':
        setWebsiteUrl(analysis.userInput);
        setProductDescription('');
        setIndustry('');
        setKeywords('');
        break;
    }
    setActiveView('marketResearch');
  };

  const renderMarketResearchView = () => (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-full">
      <div className="lg:col-span-4 xl:col-span-3 h-full">
          <div className="sticky top-6">
            <InputForm
              productDescription={productDescription}
              setProductDescription={setProductDescription}
              industry={industry}
              setIndustry={setIndustry}
              geographicalFocus={geographicalFocus}
              setGeographicalFocus={setGeographicalFocus}
              onAnalyze={handleAnalysis}
              isLoading={isLoadingAnalysis}
              analysisType={analysisType}
              setAnalysisType={setAnalysisType}
              keywords={keywords}
              setKeywords={setKeywords}
              websiteUrl={websiteUrl}
              setWebsiteUrl={setWebsiteUrl}
            />
          </div>
      </div>
      <div className="lg:col-span-8 xl:col-span-9 h-full">
        {isLoadingAnalysis ? (
            <div className="flex items-center justify-center h-full rounded-2xl bg-card border border-border">
                <LoadingSpinner />
            </div>
        ) : error && !analysisResult ? (
            <div className="flex items-center justify-center h-full rounded-2xl bg-card border border-border">
                <div className="bg-red-500/10 border border-red-500/20 text-red-500 px-4 py-3 rounded-lg text-center" role="alert">
                    <p className="font-semibold">Hiba történt</p>
                    <p className="text-sm mt-1">{error}</p>
                </div>
            </div>
        ) : analysisResult ? (
            <AnalysisResultDisplay 
                result={analysisResult}
                userInput={currentUserInput}
                analysisType={analysisType}
                theme={theme}
                onSave={handleSaveAnalysis}
                isSaved={isCurrentResultSaved}
                marketingStrategy={marketingStrategy}
                setMarketingStrategy={setMarketingStrategy}
                businessPlans={businessPlans}
                setBusinessPlans={setBusinessPlans}
                brandIdentity={brandIdentity}
                setBrandIdentity={setBrandIdentity}
                productNames={productNames}
                setProductNames={setProductNames}
            />
        ) : (
            <div className="flex flex-col items-center justify-center h-full rounded-2xl bg-card text-center p-8">
                <div className="w-16 h-16 p-3 mb-6 bg-background rounded-2xl border border-border flex items-center justify-center">
                    <LogoIcon />
                </div>
                <h2 className="text-3xl font-bold text-card-foreground">Piackutatás AI-val, 1 kattintásra</h2>
                <p className="mt-3 text-muted-foreground max-w-xl">
                    Használja a bal oldali vezérlőpultot egy új elemzés indításához. Adja meg termékét, szolgáltatását vagy egy témakört, és az AI elvégzi a kutatást, majd egy átfogó, vizuális irányítópulton jeleníti meg az eredményeket.
                </p>
            </div>
        )}
      </div>
    </div>
  );

  return (
    <div className="flex h-screen w-full bg-background">
      <Sidebar activeView={activeView} setActiveView={setActiveView} theme={theme} setTheme={setTheme} />
      <main className="flex-1 h-full overflow-y-auto p-6">
        {activeView === 'marketResearch' && renderMarketResearchView()}
        {activeView === 'ideaMentor' && <IdeaMentorView />}
        {activeView === 'contentGenerator' && <ContentGeneratorView analysisResult={analysisResult} userInput={currentUserInput} theme={theme} brandIdentity={brandIdentity} />}
        {activeView === 'marketingStrategy' && <MarketingStrategyView />}
        {activeView === 'analysisHistory' && <AnalysisHistoryView analyses={savedAnalyses} onView={handleViewSavedAnalysis} onDelete={handleDeleteAnalysis} theme={theme} />}
        {activeView === 'calendar' && <CalendarView marketingStrategy={marketingStrategy} />}
      </main>
    </div>
  );
};

export default App;

import React, { ErrorInfo, ReactNode } from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
  errorInfo: ErrorInfo | null;
}

class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = {
      hasError: false,
      error: null,
      errorInfo: null
    };
  }

  static getDerivedStateFromError(error: Error): Partial<ErrorBoundaryState> {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
    this.setState({ errorInfo });
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: '20px', color: '#ef4444', fontFamily: 'sans-serif', backgroundColor: '#1e293b', minHeight: '100vh', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center' }}>
          <div style={{ maxWidth: '600px', width: '100%' }}>
            <h1 style={{ fontSize: '24px', marginBottom: '16px', textAlign: 'center' }}>Hiba történt az alkalmazás betöltésekor.</h1>
            <div style={{ backgroundColor: 'rgba(239, 68, 68, 0.1)', padding: '20px', borderRadius: '12px', border: '1px solid rgba(239, 68, 68, 0.2)' }}>
              <p style={{ fontWeight: 'bold', marginBottom: '12px', fontSize: '16px' }}>{this.state.error?.message}</p>
              <pre style={{ fontSize: '12px', overflow: 'auto', color: '#fca5a5', whiteSpace: 'pre-wrap', maxHeight: '300px' }}>
                {this.state.errorInfo?.componentStack}
              </pre>
            </div>
            <button 
              onClick={() => window.location.reload()} 
              style={{ marginTop: '24px', width: '100%', padding: '12px 24px', backgroundColor: '#3b82f6', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold', fontSize: '16px', transition: 'background-color 0.2s' }}
            >
              Oldal újratöltése
            </button>
          </div>
        </div>
